    /**
     * Private default constructor - part of the Singleton Design Pattern.
     * Called at initialization only, constructs the single private instance.
     */
    private SvgPaths() {
        Debug.trace(DD, "SvgPaths constructed.");
        model = Model.getInstance();
    }

    /**
     * Singleton implementation.
     * @return the only instance of the model.
     */
    public static SvgPaths getInstance() {return instance; }


    public static SvgPathData getSvgPathData(int index) {
        if (index < 0 || index >= svgPathData.length) {
            Debug.major(DD, "getSvgPathData() - invalid index: " + index);
            return null;
        }
        return svgPathData[index];
    }

    public static SvgPathData getSvgPathData(String symbol) {
        for (int i = 0; i < svgPathData.length; i++) {
            if (svgPathData[i].isSymbol(symbol)) {
                return svgPathData[i];
            }
        }

        Debug.major(DD, "getSvgPathData() - invalid symbol: " + symbol);
        return null;
    }

    public SvgPathData getSvgPathData(Item item) {
        String symbol = model.getStandardSymbol(item);

        return getSvgPathData(symbol);
    }

    public String getSvgPath(Item item) {
        String symbol = model.getStandardSymbol(item);

        return getSvgPathData(symbol).getPath();
    }

